#include <stdio.h>
#include <string.h>
#include <gmp.h>
#include <mpfr.h>

int main() {
    mpfr_t num;
    mpfr_init2(num, 1000000);

    int a, b, c;
    scanf("%d %d %d", &a, &b, &c);

    mpfr_set_si(num, a, MPFR_RNDN);
    mpfr_div_si(num, num, b, MPFR_RNDN);

    char *d = mpfr_get_str(NULL, NULL, 10, 0, num, MPFR_RNDN);

    int found = 0;
    int where = 0;
    int pos = -2;
    int at = 0;

    for (int i = 0; i < strlen(d); i++) {
        if (at == 999999) {
            break;
        }
        if (d[i] == '.') {
            found = 1;
            where = at;
            continue;
        }
        if (!found) {
            continue;
        }
        if (d[i] == c + '0') {
            pos = at - where;
            break;
        }
        at++;
    }

    if (pos == -2 && c == 0 && at < 999999) {
        pos = at;
    }

    printf("%d\n", pos + 1);

    mpfr_free_str(d);
    mpfr_clear(num);

    return 0;
}
